package main

import (
	"fmt"
	"sync"
)

type Bank struct {
	balances map[string]int64
	mu       sync.Mutex
}

func NewBank() *Bank {
	return &Bank{
		balances: make(map[string]int64),
	}
}

func (b *Bank) Deposit(account string, amount int64) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.balances[account] += amount
}

func (b *Bank) Withdraw(account string, amount int64) error {
	b.mu.Lock()
	defer b.mu.Unlock()
	if b.balances[account] < amount {
		return fmt.Errorf("insufficient balance")
	}
	b.balances[account] -= amount
	return nil
}

func (b *Bank) Balance(account string) int64 {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.balances[account]
}

func main() {
	bank := NewBank()

	var wg sync.WaitGroup

	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			bank.Deposit(fmt.Sprintf("user%d", i), 100)
		}(i)
	}

	for i := 0; i < 5; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			err := bank.Withdraw(fmt.Sprintf("user%d", i), 50)
			if err != nil {
				fmt.Println(err)
			}
		}(i)
	}

	wg.Wait()

	for i := 0; i < 10; i++ {
		fmt.Printf("Balance for user%d: %d\n", i, bank.Balance(fmt.Sprintf("user%d", i)))
	}
}